  ('medical-tech-moex-20918', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '取得病人血液檢體後，等待凝固再經過離心取得的血清當中若有紅血球混合時，則應該如何處理？ 直接做實驗    直接保存在-20℃冰箱 加入醋酸溶解紅血球    再離心一次以取得上清的血清', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20919', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於細胞激素（cytokines）的敘述，何者錯誤？ 一種細胞激素可以作用於多種免疫細胞 多種細胞激素可以作用於一種免疫細胞，引起相同之反應 某些免疫反應，如抗體轉換（antibody class switching）須多種細胞激素合作於B細胞才得完成 細胞激素相互之間，有加成作用，但無互相拮抗的作用', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-20920', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '何種抗體可用來純化T細胞？ Anti-CD3  Anti-CD19  Anti-CD45  Anti-CD80', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "1d862fed5162", "answer_pdf_sha1": "5c7487e6a69d", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
